    putText('adminLastUpdated',`Updated ${formatLagos(payload.generated_at||Date.now())} WAT · verified Admin V2 snapshot`);

    const sourceIssues=Object.entries(payload.sources||{})
      .filter(([,value])=>value&&value.ok===false)
